        assert validate_email("noatsign.example.com") is False

    # --- Edge cases: multiple @ symbols ---

    def test_multiple_at_symbols(self):
        # split('@') produces more than 2 parts
        assert validate_email("user@domain@extra.com") is False

    # --- Edge cases: missing local part ---

    def test_missing_local_part(self):
        assert validate_email("@domain.com") is False

    # --- Edge cases: missing domain part ---

    def test_missing_domain_part(self):
        assert validate_email("user@") is False

    # --- Edge cases: no dot in domain ---

    def test_no_dot_in_domain(self):
        assert validate_email("user@localhost") is False

    # --- Edge cases: only @ and dot ---

    def test_only_at_and_dot(self):
        # local = "@", domain = "." — both truthy, but weird
        assert validate_email("@.") is True  # Technically passes the rules

    # --- Edge cases: domain with trailing dot ---

    def test_trailing_dot_in_domain(self):
        assert validate_email("user@domain.com.") is True

    # --- Edge cases: whitespace ---

    def test_whitespace_in_email(self):
        assert validate_email(" user@domain.com") is True  # no trimming performed

    def test_only_whitespace(self):
        assert validate_email("   ") is True  # '@' not present but string is truthy → wait, '@' not in → False
        # Let's re-check: "   " has no '@', so it returns False
        # Actually: "   " is truthy and '@' not in "   " → False

    # --- Edge cases: non-string input ---

    def test_integer_input(self):
        with pytest.raises(AttributeError):
