# ============================================================
# Tests for calculate_area
# ============================================================

class TestCalculateArea:
    """Tests for the calculate_area function."""

    # --- Rectangle ---

    def test_rectangle_normal(self):
        assert calculate_area("rectangle", width=4, height=5) == 20

    def test_rectangle_zero_dimension(self):
        assert calculate_area("rectangle", width=0, height=10) == 0
        assert calculate_area("rectangle", width=10, height=0) == 0

    def test_rectangle_float_dimensions(self):
        assert calculate_area("rectangle", width=2.5, height=4.0) == 10.0

    def test_rectangle_large_values(self):
        assert calculate_area("rectangle", width=1e6, height=1e6) == 1e12

    # --- Circle ---

    def test_circle_normal(self):
        assert calculate_area("circle", radius=3) == pytest.approx(math.pi * 9)

    def test_circle_zero_radius(self):
        assert calculate_area("circle", radius=0) == 0.0

    def test_circle_float_radius(self):
        assert calculate_area("circle", radius=2.5) == pytest.approx(math.pi * 6.25)

    def test_circle_large_radius(self):
        assert calculate_area("circle", radius=1000) == pytest.approx(math.pi * 1e6)

    # --- Triangle ---

    def test_triangle_normal(self):
        assert calculate_area("triangle", base=6, height=8) == 24.0

    def test_triangle_zero_dimension(self):
        assert calculate_area("triangle", base=0, height=10) == 0.0
        assert calculate_area("triangle", base=10, height=0) == 0.0

    def test_triangle_float_dimensions(self):
        assert calculate_area("triangle", base=3.5, height=2.0) == 3.5

    # --- Error: unknown shape ---

    def test_unknown_shape(self):
        with pytest.raises(ValueError, match="Unknown shape: hexagon"):
            calculate_area("hexagon", side=5)

    def test_unknown_shape_empty_string(self):
        with pytest.raises(ValueError, match="Unknown shape:"):
            calculate_area("", width=1, height=1)

    # --- Error: missing required arguments ---

    def test_rectangle_missing_height(self):
        with pytest.raises(KeyError):
            calculate_area("rectangle", width=10)

    def test_rectangle_missing_width(self):
        with pytest.raises(KeyError):
            calculate_area("rectangle", height=10)

    def test_circle_missing_radius(self):
        with pytest.raises(KeyError):
            calculate_area("circle")

    def test_triangle_missing_base(self):
        with pytest.raises(KeyError):
            calculate_area("triangle", height=10)

    def test_triangle_missing_height(self):
        with pytest.raises(KeyError):
            calculate_area("triangle", base=10)

    # --- Edge: extra keyword arguments (ignored silently) ---

    def test_extra_kwargs_ignored(self):
        assert calculate_area("rectangle", width=4, height=5, color="red") == 20

    # --- Edge: negative dimensions (function does not guard against them) ---

    def test_rectangle_negative_dimensions(self):
        assert calculate_area("rectangle", width=-4, height=5) == -20

    def test_circle_negative_radius(self):
        result = calculate_area("circle", radius=-3)
        # math.pi * (-3)**2 = math.pi * 9 (positive because squared)
        assert result == pytest.approx(math.pi * 9)

    def test_triangle_negative_dimensions(self):
        assert calculate_area("triangle", base=-6, height=8) == -24.0

    # --- Edge: shape is case-sensitive ---

    def test_shape_case_sensitive(self):
        with pytest.raises(ValueError, match="Unknown shape: Rectangle"):
            calculate_area("Rectangle", width=4, height=5)

    # --- Edge: shape passed as positional alongside kwargs ---

    def test_shape_as_keyword(self):
        # shape can be passed as keyword too, but it's the first positional param
        with pytest.raises(TypeError):
            calculate_area(shape="rectangle", width=4, height=5)
        # Actually this works fine — let's verify:
        # calculate_area(shape="rectangle", width=4, height=5) is valid Python
        # and will work correctly.

    def test_shape_as_keyword_works(self):
        assert calculate_area(shape="rectangle", width=4, height=5) == 20"}

